package kr.co.iei.admin.model.dao; import kr.co.iei.admin.model.vo.*; import lombok.RequiredArgsConstructor; import org.apache.ibatis.session.SqlSession; import org.springframework.stereotype.Repository; import java.util.*; @Repository @RequiredArgsConstructor public class AdminDao { private final SqlSession sqlSession; public AdminSummary selectSummary(){ return sqlSession.selectOne("admin.selectSummary"); } public List<AdminMemberResponse> selectMembers(){ return sqlSession.selectList("admin.selectMembers"); } public List<AdminMeetingResponse> selectMeetings(){ return sqlSession.selectList("admin.selectMeetings"); } public List<AdminReportResponse> selectReports(){ return sqlSession.selectList("admin.selectReports"); } public int updateReportStatus(Long reportId,String status){ return sqlSession.update("admin.updateReportStatus", Map.of("reportId",reportId,"status",status)); } }
